import{c as n,S as i,j as e,m as h}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Tài khoản và vai trò","description":"","frontmatter":{},"headers":[],"relativePath":"gioi-thieu/tai-khoan-va-vai-tro.md","filePath":"gioi-thieu/tai-khoan-va-vai-tro.md","lastUpdated":0}'),a={name:"gioi-thieu/tai-khoan-va-vai-tro.md"};function c(o,t,r,l,d,g){return i(),e("div",null,[...t[0]||(t[0]=[h('<h1 id="tai-khoan-va-vai-tro" tabindex="-1">Tài khoản và vai trò <a class="header-anchor" href="#tai-khoan-va-vai-tro" aria-label="Permalink to “Tài khoản và vai trò”">​</a></h1><p>Hệ thống LamSơn Edutech có <strong>3 vai trò chính</strong>, mỗi vai trò có cổng đăng nhập và khu vực làm việc riêng biệt.</p><h2 id="_1-hoc-vien-student" tabindex="-1">1. Học viên (Student) <a class="header-anchor" href="#_1-hoc-vien-student" aria-label="Permalink to “1. Học viên (Student)”">​</a></h2><p><strong>Đối tượng:</strong> Học sinh THCS, THPT, thí sinh ôn thi đại học, người tự học.</p><p><strong>Có thể làm:</strong></p><ul><li>Đăng ký tài khoản miễn phí.</li><li>Mua / nhận miễn phí khóa học, học liệu.</li><li>Học bài giảng, làm bài luyện tập.</li><li>Làm bài thi thử ĐGNL, ĐGTD, Tốt nghiệp THPT, kiểm tra đầu vào.</li><li>Xem lại đáp án, lịch sử và bảng xếp hạng.</li><li>Đặt câu hỏi cho giáo viên trong khóa học.</li></ul><p><strong>Cổng đăng nhập:</strong> trang chủ hệ thống (<code>https://lamsonedutech.vn/auth/hocvien</code> hoặc nút <strong>Đăng nhập</strong> ở góc phải).</p><h2 id="_2-giao-vien-teacher" tabindex="-1">2. Giáo viên (Teacher) <a class="header-anchor" href="#_2-giao-vien-teacher" aria-label="Permalink to “2. Giáo viên (Teacher)”">​</a></h2><p><strong>Đối tượng:</strong> Giáo viên chuyên môn, gia sư cộng tác.</p><p><strong>Có thể làm:</strong></p><ul><li>Tạo và quản lý các khóa học do mình phụ trách.</li><li>Soạn chương học → chuyên đề → bài giảng (video, văn bản, file).</li><li>Tạo tiêu chí đề thi, ra đề luyện tập / đề kiểm tra cuối chuyên đề.</li><li>Quản lý lớp học và học viên trong lớp.</li><li>Chấm và xem điểm thi của học viên.</li><li>Trả lời câu hỏi của học viên (Hỏi đáp).</li></ul><p><strong>Cổng đăng nhập:</strong> <code>https://lamsonedutech.vn/auth/giaovien</code> hoặc liên kết được quản trị viên cung cấp.</p><h2 id="_3-quan-tri-vien-admin-staff" tabindex="-1">3. Quản trị viên (Admin / Staff) <a class="header-anchor" href="#_3-quan-tri-vien-admin-staff" aria-label="Permalink to “3. Quản trị viên (Admin / Staff)”">​</a></h2><p><strong>Đối tượng:</strong> Người quản lý hệ thống. Có thể chia thành nhiều cấp quyền (Quản trị, Nhân viên kinh doanh, Nhân viên nội dung…) qua <strong>Quản lý quyền</strong>.</p><p><strong>Có thể làm:</strong></p><ul><li>Quản lý toàn bộ tài khoản: học viên, giáo viên, nhân viên.</li><li>Quản lý đào tạo: khung chương trình, khóa học, chương, chuyên đề, bài giảng.</li><li>Quản lý đề thi: tiêu chí, trích đoạn, đề ôn khóa học, đề mẫu luyện thi, đánh giá, câu hỏi, bộ đề.</li><li>Quản lý kinh doanh: khuyến mãi, chiết khấu, đại lý, hóa đơn, học viên - khóa học.</li><li>Cấu hình hệ thống: banner, menu, footer, ngân hàng, liên hệ.</li><li>Xem thống kê tổng thể của toàn hệ thống.</li></ul><p><strong>Cổng đăng nhập:</strong> <code>https://lamsonedutech.vn/auth/admin</code> (riêng cho quản trị).</p><h2 id="so-sanh-nhanh-quyen-han" tabindex="-1">So sánh nhanh quyền hạn <a class="header-anchor" href="#so-sanh-nhanh-quyen-han" aria-label="Permalink to “So sánh nhanh quyền hạn”">​</a></h2><table tabindex="0"><thead><tr><th>Tính năng</th><th style="text-align:center;">Học viên</th><th style="text-align:center;">Giáo viên</th><th style="text-align:center;">Admin</th></tr></thead><tbody><tr><td>Học bài giảng, làm bài thi</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅ (xem trước)</td><td style="text-align:center;">✅</td></tr><tr><td>Tạo khóa học, soạn bài giảng</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅ (khóa do mình phụ trách)</td><td style="text-align:center;">✅ (toàn bộ)</td></tr><tr><td>Tạo / sửa đề thi</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅ (theo khóa)</td><td style="text-align:center;">✅ (toàn bộ)</td></tr><tr><td>Quản lý lớp học</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅ (lớp được giao)</td><td style="text-align:center;">✅</td></tr><tr><td>Chấm / xem điểm thi học viên</td><td style="text-align:center;">Bản thân</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Quản lý tài khoản người khác</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td>Quản lý kinh doanh, hóa đơn</td><td style="text-align:center;">Hóa đơn của mình</td><td style="text-align:center;">Chiết khấu của mình</td><td style="text-align:center;">✅</td></tr><tr><td>Cấu hình hệ thống (banner, menu...)</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr></tbody></table><h2 id="phan-quyen-chi-tiet-chi-admin" tabindex="-1">Phân quyền chi tiết (chỉ Admin) <a class="header-anchor" href="#phan-quyen-chi-tiet-chi-admin" aria-label="Permalink to “Phân quyền chi tiết (chỉ Admin)”">​</a></h2><p>Trong vai trò <strong>Admin</strong>, hệ thống còn cho phép tạo nhiều <strong>chức vụ (position)</strong> với từng quyền cụ thể như: <code>student</code>, <code>teacher</code>, <code>staff</code>, <code>course</code>, <code>lesson</code>, <code>exam</code>, <code>examSet</code>, <code>program</code>, <code>modun</code>, <code>thematic</code>, <code>comment</code>, <code>discountCode</code>, <code>dealerDiscount</code>, <code>invoice</code>, <code>footer</code>, <code>contact</code>, …</p><p>Xem chi tiết tại <a href="/admin/phan-quyen">Phân quyền (Admin)</a>.</p><h2 id="mot-nguoi-co-the-co-nhieu-vai-tro-khong" tabindex="-1">Một người có thể có nhiều vai trò không? <a class="header-anchor" href="#mot-nguoi-co-the-co-nhieu-vai-tro-khong" aria-label="Permalink to “Một người có thể có nhiều vai trò không?”">​</a></h2><p>Có. Hệ thống cho phép 1 cá nhân có thể đăng ký nhiều tài khoản khác nhau cho từng vai trò (ví dụ một giáo viên có thể tạo thêm tài khoản học viên để thử trải nghiệm khóa học). Tuy nhiên, <strong>mỗi tài khoản chỉ thuộc một vai trò</strong> và đăng nhập ở cổng tương ứng.</p><h2 id="tiep-theo" tabindex="-1">Tiếp theo <a class="header-anchor" href="#tiep-theo" aria-label="Permalink to “Tiếp theo”">​</a></h2><ul><li><a href="./dang-nhap">Cách đăng nhập / đăng ký</a></li><li><a href="./cac-loai-ky-thi">Các loại kỳ thi</a></li></ul>',26)])])}const m=n(a,[["render",c]]);export{u as __pageData,m as default};
